challenge.solution:
function Alert({ variant = 'info', title, children }) {
  const styles = {
    info: {
      backgroundColor: '#dbeafe',
      borderColor: '#3b82f6',
      color: '#1e40af',
    },
    warning: {
      backgroundColor: '#fef3c7',
      borderColor: '#f59e0b',
      color: '#92400e',
    },
    error: {
      backgroundColor: '#fee2e2',
      borderColor: '#ef4444',
      color: '#991b1b',
    },
  };

  const currentStyle = styles[variant];

  return (
    <div
      style={{
        padding: '16px',
        borderRadius: '8px',
        borderLeft: `4px solid ${currentStyle.borderColor}`,
        backgroundColor: currentStyle.backgroundColor,
        color: currentStyle.color,
      }}
    >
      {title && (
        <h3 style={{ margin: '0 0 8px', fontWeight: 'bold', fontSize: '16px' }}>
          {title}
        </h3>
      )}
      <div>{children}</div>
    </div>
  );
}

function App() {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', padding: '20px' }}>
      <Alert variant="info" title="Informação">
        <p>Sua conta foi criada com sucesso.</p>
      </Alert>

      <Alert variant="warning" title="Atenção">
        <p>Seu plano expira em 3 dias.</p>
      </Alert>

      <Alert variant="error" title="Erro">
        <p>Não foi possível salvar as alterações.</p>
      </Alert>
    </div>
  );
}
